// OpenCL kernel for kmeans clustering partial sums and membership assignment

__kernel void kmeans_assign(
    __global const float* features,       // Flattened features array: npoints * nfeatures
    __global const float* clusters,       // Flattened clusters array: nclusters * nfeatures
    __global int* membership,              // Membership array: npoints
    __global float* partial_new_centers,  // Partial sums: nthreads * nclusters * nfeatures
    __global int* partial_new_centers_len,// Partial counts: nthreads * nclusters
    const int npoints,
    const int nfeatures,
    const int nclusters,
    const int nthreads)
{
    int gid = get_global_id(0);
    int tid = get_global_id(1); // thread id in second dimension
    if (gid >= npoints) return;

    // Find nearest cluster
    int nearest = 0;
    float min_dist = FLT_MAX;
    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int f = 0; f < nfeatures; f++) {
            float diff = features[gid * nfeatures + f] - clusters[c * nfeatures + f];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            nearest = c;
        }
    }

    // Update membership
    int old_membership = membership[gid];
    membership[gid] = nearest;

    // Atomically update partial sums and counts for this thread
    // partial_new_centers_len and partial_new_centers are indexed by tid, cluster, feature
    // Compute base indices
    int base_len_idx = tid * nclusters + nearest;
    atomic_inc(&partial_new_centers_len[base_len_idx]);

    for (int f = 0; f < nfeatures; f++) {
        int base_center_idx = tid * nclusters * nfeatures + nearest * nfeatures + f;
        // Atomic add for float is not standard in OpenCL 1.x, but OpenCL 2.0 supports atomic_add on floats
        // Use atomic_add for float if supported, else use atomic_add on int representation (not done here)
        atomic_add(&partial_new_centers[base_center_idx], features[gid * nfeatures + f]);
    }
}

__kernel void kmeans_reduce(
    __global float* partial_new_centers,  // nthreads * nclusters * nfeatures
    __global int* partial_new_centers_len,// nthreads * nclusters
    __global float* new_centers,           // nclusters * nfeatures
    __global int* new_centers_len,         // nclusters
    const int nthreads,
    const int nclusters,
    const int nfeatures)
{
    int c = get_global_id(0);
    if (c >= nclusters) return;

    int sum_len = 0;
    for (int t = 0; t < nthreads; t++) {
        int idx_len = t * nclusters + c;
        sum_len += partial_new_centers_len[idx_len];
        partial_new_centers_len[idx_len] = 0;
    }
    new_centers_len[c] = sum_len;

    for (int f = 0; f < nfeatures; f++) {
        float sum_val = 0.0f;
        for (int t = 0; t < nthreads; t++) {
            int idx_center = t * nclusters * nfeatures + c * nfeatures + f;
            sum_val += partial_new_centers[idx_center];
            partial_new_centers[idx_center] = 0.0f;
        }
        new_centers[c * nfeatures + f] = sum_val;
    }
}

__kernel void kmeans_update_clusters(
    __global float* clusters,           // nclusters * nfeatures
    __global float* new_centers,        // nclusters * nfeatures
    __global int* new_centers_len,      // nclusters
    const int nclusters,
    const int nfeatures)
{
    int c = get_global_id(0);
    if (c >= nclusters) return;

    int len = new_centers_len[c];
    if (len > 0) {
        for (int f = 0; f < nfeatures; f++) {
            clusters[c * nfeatures + f] = new_centers[c * nfeatures + f] / (float)len;
            new_centers[c * nfeatures + f] = 0.0f;
        }
    }
    new_centers_len[c] = 0;
}
